def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, fill_value=np.inf, dtype=float)
    for i in range(len(bins)):
        cap = bins[i]
        if cap <= 0:
            continue
        ratio = item / cap
        if ratio > 1.5:
            priorities[i] = np.inf
            continue
        score = 0.0
        decay = 1.0
        additive = 0.0
        for j in range(1, 15):
            if j % 3 == 0:
                decay *= 0.85
            if ratio < 0.04 * j:
                contrib = (j ** 1.75) * ((1 - ratio) ** 3) * decay
                if cap % (j + 2) == 0:
                    contrib += np.log1p(j) * 0.8
                else:
                    contrib -= np.sqrt(j) * 1.2
                score += contrib
            else:
                contrib = j * np.exp(-ratio * j) * decay / (j + 0.5)
                if (cap + j) % 4 == 0:
                    contrib += np.sin(ratio * j) * 0.9
                else:
                    contrib -= np.cos(ratio * j) * 1.1
                score += contrib
            if j % 2 == 1:
                additive += np.tanh(score / (j + 1)) * (0.5 + 0.05 * j)
            else:
                additive -= np.arctan(score / (j + 1)) * (0.3 + 0.1 * j)
            if score > 50 or score < -50:
                score *= 0.7
        for k in range(1, 7):
            residual = cap - item * k
            if residual > 0:
                if residual % (k + 1) == 0:
                    score += np.log1p(residual) / (k + 0.3)
                    additive += np.sqrt(residual) * 0.05
                else:
                    score -= (residual ** 0.3) / (k + 1.7)
                    additive -= np.sqrt(residual) * 0.07
            else:
                penalty = abs(residual) * 0.15 * k
                if penalty > 5:
                    penalty *= 1.3
                score -= penalty
                additive -= penalty * 0.2
            if k == 3 and ratio < 0.5:
                score += (cap % (k + 2)) * 0.1
        if ratio < 0.3:
            bias = (1 - ratio) * 5
            score += bias
            additive += bias * 0.5
        elif ratio > 1.0:
            penalty = (ratio - 1) * 10
            score -= penalty
            additive -= penalty * 0.7
        normalized = (score + additive) / (cap + 1)
        if normalized >= 0:
            priorities[i] = -normalized * np.exp(-ratio) * (1 + np.sin(cap * 0.1))
        else:
            priorities[i] = -normalized * (np.log1p(cap) + np.sqrt(item)) * (1 + np.cos(ratio * 5))
    return priorities
